      "path": "src/modules/projects/routes.js",
      "content": "const express = require('express');
const { createProject, getProjects, getProjectById } = require('./service');
const router = express.Router();

router.get('/', (req, res) => {
  const projects = getProjects();
  res.status(200).json({ projects });
});

router.post('/', (req, res) => {
  try {
    const project = createProject(req.body.name);
    res.status(201).json({ project });
  } catch (error) {
    res.status(error.code === 'duplicate' ? 409 : 400).json({ error: { code: error.code, message: error.message } });
  }
});

router.get('/:projectId', (req, res) => {
  try {
    const project = getProjectById(req.params.projectId);
    res.status(200).json({ project });
  } catch (error) {
    res.status(404).json({ error: { code: 'not_found', message: error.message } });
  }
});

module.exports = router;
